import React, { useState, useEffect } from 'react';
import { X, ExternalLink, Globe, Smartphone, Monitor } from 'lucide-react';
import { Project, ProjectLink } from '../types';

interface ProjectModalProps {
  project: Project | null;
  onClose: () => void;
}

const ProjectModal: React.FC<ProjectModalProps> = ({ project, onClose }) => {
  const [activeLink, setActiveLink] = useState<ProjectLink | null>(null);
  const [isLoading, setIsLoading] = useState(true);

  // Set initial active link when project opens
  useEffect(() => {
    if (project && project.links.length > 0) {
      setActiveLink(project.links[0]);
      setIsLoading(true);
    }
  }, [project]);

  // Reset loading when switching links inside the modal
  const handleLinkSwitch = (link: ProjectLink) => {
    if (activeLink?.url !== link.url) {
      setIsLoading(true);
      setActiveLink(link);
    }
  };

  if (!project || !activeLink) return null;

  return (
    <div className="fixed inset-0 z-50 flex flex-col bg-black/95 backdrop-blur-sm animate-in fade-in duration-200">
      {/* Modal Header / Toolbar */}
      <div className="flex flex-col md:flex-row items-center justify-between p-4 bg-[#0a0a0a] border-b border-white/10 shadow-xl z-50 gap-4">

        {/* Left: Title & Version Switcher */}
        <div className="flex flex-col md:flex-row items-start md:items-center gap-4 w-full md:w-auto">
          <div>
            <h3 className="text-lg font-bold text-white tracking-tight">{project.title}</h3>
            <p className="text-xs text-gray-400 hidden md:block">Interactive Preview</p>
          </div>

          {/* Version Switcher (Only if multiple links exist) */}
          {project.links.length > 1 && (
            <div className="flex p-1 bg-white/5 rounded-lg border border-white/10 overflow-x-auto max-w-full no-scrollbar">
              {project.links.map((link) => (
                <button
                  key={link.url}
                  onClick={() => handleLinkSwitch(link)}
                  className={`px-3 py-1.5 text-xs font-medium rounded-md transition-all whitespace-nowrap ${
                    activeLink.url === link.url
                      ? 'bg-blue-600 text-white shadow-lg'
                      : 'text-gray-400 hover:text-white hover:bg-white/5'
                  }`}
                >
                  {link.label}
                </button>
              ))}
            </div>
          )}
        </div>

        {/* Right: Actions */}
        <div className="flex items-center gap-3 w-full md:w-auto justify-end">
          <a
            href={activeLink.url}
            target="_blank"
            rel="noopener noreferrer"
            className="flex items-center gap-2 px-4 py-2 text-sm font-medium text-blue-400 bg-blue-500/10 rounded-full hover:bg-blue-500/20 hover:text-blue-300 transition-colors border border-blue-500/20"
          >
            <span>Open in New Window</span>
            <ExternalLink size={14} />
          </a>
          <button
            onClick={onClose}
            className="p-2 text-gray-400 hover:text-white hover:bg-red-500/20 hover:text-red-400 rounded-full transition-all"
            aria-label="Close Preview"
          >
            <X size={24} />
          </button>
        </div>
      </div>

      {/* Main Content Area (Iframe) */}
      <div className="flex-1 relative w-full h-full bg-[#121212] overflow-hidden">
        {isLoading && (
          <div className="absolute inset-0 flex items-center justify-center z-10">
            <div className="flex flex-col items-center gap-3">
              <div className="w-10 h-10 border-4 border-blue-500/30 border-t-blue-500 rounded-full animate-spin"></div>
              <p className="text-sm text-gray-500 animate-pulse">Establishing Connection...</p>
            </div>
          </div>
        )}

        <iframe
          src={activeLink.url}
          className="w-full h-full border-0"
          title={`Preview of ${project.title}`}
          onLoad={() => setIsLoading(false)}
          allow="accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture"
          sandbox="allow-same-origin allow-scripts allow-forms allow-popups"
        />

        {/* Floating helper for connection issues */}
        {!isLoading && (
          <div className="absolute bottom-6 left-1/2 -translate-x-1/2 bg-black/60 backdrop-blur-md text-gray-400 text-xs px-4 py-2 rounded-full border border-white/5 pointer-events-none">
            If content fails to load, use the "Open in New Window" button.
          </div>
        )}
      </div>
    </div>
  );
};

export default ProjectModal;

