import React, { useState } from 'react';
import Hero from './components/Hero';
import Methodology from './components/Methodology';
import ProjectGallery from './components/ProjectGallery';
import Testimonials from './components/Testimonials';
import Footer from './components/Footer';
import ProjectModal from './components/ProjectModal';
import { Project } from './types';

const App: React.FC = () => {
  const [activeProject, setActiveProject] = useState<Project | null>(null);

  const openModal = (project: Project) => {
    setActiveProject(project);
    // Prevent background scrolling
    document.body.style.overflow = 'hidden';
  };

  const closeModal = () => {
    setActiveProject(null);
    // Restore scrolling
    document.body.style.overflow = 'auto';
  };

  return (
    <div className="bg-[#050505] min-h-screen text-slate-200 selection:bg-blue-500/30">
      <main>
        <Hero />
        <Methodology />
        <ProjectGallery onProjectClick={openModal} />
        <Testimonials />
      </main>
      <Footer />

      {/* Modal renders conditionally but handled within component for animation/unmount logic if needed */}
      {activeProject && (
        <ProjectModal 
          project={activeProject} 
          onClose={closeModal} 
        />
      )}
    </div>
  );
};

export default App;

