import React, { useState, useEffect } from 'react';
import { X, ExternalLink, Download } from 'lucide-react';
import { Project, ProjectLink } from '../types';
import { useLanguage } from '../contexts/LanguageContext';

interface ProjectModalProps {
  project: Project | null;
  onClose: () => void;
}

const ProjectModal: React.FC<ProjectModalProps> = ({ project, onClose }) => {
  const [activeLink, setActiveLink] = useState<ProjectLink | null>(null);
  const [isLoading, setIsLoading] = useState(true);
  const { t, language } = useLanguage();

  // Separate app links from download links
  const appLinks = project ? project.links.filter(l => l.type !== 'download') : [];
  const downloadLinks = project ? project.links.filter(l => l.type === 'download') : [];

  // Set initial active link when project opens
  useEffect(() => {
    if (project && appLinks.length > 0) {
      setActiveLink(appLinks[0]);
      setIsLoading(true);
    }
  }, [project]);

  // Reset loading when switching links inside the modal
  const handleLinkSwitch = (link: ProjectLink) => {
    if (activeLink?.url !== link.url) {
      setIsLoading(true);
      setActiveLink(link);
    }
  };

  if (!project || !activeLink) return null;

  return (
    <div className="fixed inset-0 z-50 flex flex-col bg-gray-100/30 backdrop-blur-xl animate-fade-in">
      {/* Modal Header / Toolbar */}
      <div className="flex flex-col md:flex-row items-center justify-between p-4 bg-white/70 backdrop-blur-md border-b border-white/40 shadow-sm z-50 gap-4">

        {/* Left: Title & Version Switcher */}
        <div className="flex flex-col md:flex-row items-start md:items-center gap-4 w-full md:w-auto">
          <div>
            <h3 className="text-lg font-bold text-[#1d1d1f] tracking-tight">
              {language === 'zh' ? project.title_zh : project.title}
            </h3>
            <p className="text-xs text-gray-500 hidden md:block">{t.modal_preview}</p>
          </div>

          {/* Version Switcher (Only if multiple app links exist) */}
          {appLinks.length > 1 && (
            <div className="flex p-1 bg-gray-200/50 rounded-lg border border-white/50 overflow-x-auto max-w-full no-scrollbar">
              {appLinks.map((link) => (
                <button
                  key={link.url}
                  onClick={() => handleLinkSwitch(link)}
                  className={`px-3 py-1.5 text-xs font-semibold rounded-md transition-all whitespace-nowrap ${
                    activeLink.url === link.url
                      ? 'bg-white text-black shadow-sm'
                      : 'text-gray-500 hover:text-black hover:bg-white/50'
                  }`}
                >
                  {language === 'zh' && link.label_zh ? link.label_zh : link.label}
                </button>
              ))}
            </div>
          )}
        </div>

        {/* Right: Actions */}
        <div className="flex items-center gap-3 w-full md:w-auto justify-end">

          {/* Download Links - Highlighted */}
          {downloadLinks.map((link) => (
             <div key={link.url} className="flex flex-col md:flex-row items-end md:items-center gap-2 mr-2">
                 <a
                    href={link.url}
                    download
                    className="flex items-center gap-2 px-5 py-2.5 text-sm font-bold text-white bg-gradient-to-r from-amber-500 to-orange-600 rounded-full hover:shadow-lg hover:scale-105 transition-all shadow-md border border-white/20"
                  >
                    <Download size={16} />
                    <span>{language === 'zh' && link.label_zh ? link.label_zh : link.label}</span>
                  </a>
                  <span className="text-[10px] text-gray-500 max-w-[120px] leading-tight text-right md:text-left hidden md:block">
                     {t.modal_download_hint}
                  </span>
             </div>
          ))}

          <a
            href={activeLink.url}
            target="_blank"
            rel="noopener noreferrer"
            className="flex items-center gap-2 px-4 py-2 text-sm font-medium text-blue-600 bg-blue-50/50 rounded-full hover:bg-blue-100/50 hover:text-blue-700 transition-colors border border-blue-100"
          >
            <span>{t.modal_open_new}</span>
            <ExternalLink size={14} />
          </a>
          <button
            onClick={onClose}
            className="p-2 text-gray-400 hover:text-black hover:bg-gray-200/50 rounded-full transition-all"
            aria-label="Close Preview"
          >
            <X size={24} />
          </button>
        </div>
      </div>

      {/* Main Content Area (Iframe) */}
      <div className="flex-1 relative w-full h-full bg-white overflow-hidden">
        {isLoading && (
          <div className="absolute inset-0 flex items-center justify-center z-10 bg-white/80 backdrop-blur-sm">
            <div className="flex flex-col items-center gap-3">
              <div className="w-10 h-10 border-4 border-blue-500/30 border-t-blue-500 rounded-full animate-spin"></div>
              <p className="text-sm text-gray-500 animate-pulse">Establishing Connection...</p>
            </div>
          </div>
        )}

        <iframe
          src={activeLink.url}
          className="w-full h-full border-0"
          title={`Preview of ${project.title}`}
          onLoad={() => setIsLoading(false)}
          allow="accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture"
          sandbox="allow-same-origin allow-scripts allow-forms allow-popups"
        />

        {/* Floating helper for connection issues */}
        {!isLoading && (
          <div className="absolute bottom-6 left-1/2 -translate-x-1/2 bg-white/80 backdrop-blur-xl text-gray-600 text-xs px-4 py-2 rounded-full border border-white/50 shadow-lg pointer-events-none">
            {t.modal_close_hint}
          </div>
        )}
      </div>
    </div>
  );
};

export default ProjectModal;

